class BaseCache:
    """Interface backbone—override storage primitives to change backend."""
    def __init__(self,maxsize:int=1024,ttl:float|None=None):
        self.maxsize,self.ttl = maxsize,ttl
        self.stats = CacheStats()
        self.log = get_logger("cache")
